+#define BUFFER_START_LENGTH 200
+
+using namespace eprosima::fastcdr;
+
+FastBuffer::FastBuffer()
+    : m_buffer(nullptr)
+    , m_bufferSize(0)
+    , m_internalBuffer(true)
+{
+}
+
+FastBuffer::FastBuffer(
+        char* const buffer,
+        const size_t bufferSize)
+    : m_buffer(buffer)
+    , m_bufferSize(bufferSize)
+    , m_internalBuffer(false)
+{
+}
+
