+// LLVM External Functions
+namespace llvm_vecsmall {
+    namespace detail {
+        /// NextPowerOf2 - Returns the next power of two (in 64-bits)
+        /// that is strictly greater than A.  Returns zero on overflow.
+        inline uint64_t NextPowerOf2(uint64_t A) {
+            A |= (A >> 1);
+            A |= (A >> 2);
+            A |= (A >> 4);
+            A |= (A >> 8);
+            A |= (A >> 16);
+            A |= (A >> 32);
+            return A + 1;
+        }
+    }
+}
